  1→import type {
  2→	DimensionAnalysisInput,
  3→	SessionAnalytics,
  4→} from "@rudel/api-routes";
  5→import type { ColumnDef } from "@tanstack/react-table";
  6→import { Activity, Clock, Timer } from "lucide-react";
  7→import { useEffect, useMemo, useState } from "react";
  8→import { useNavigate } from "react-router-dom";
  9→import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
 10→import { DatePicker } from "@/components/analytics/DatePicker";
 11→import { MultiSelect } from "@/components/analytics/MultiSelect";
 12→import { PageHeader } from "@/components/analytics/PageHeader";
 13→import { StatCard } from "@/components/analytics/StatCard";
 14→import { DimensionAnalysisChart } from "@/components/charts/DimensionAnalysisChart";
 15→import { DataTable } from "@/components/ui/data-table";
 16→import {
 17→	Select,
 18→	SelectContent,
 19→	SelectItem,
 20→	SelectTrigger,
 21→	SelectValue,
 22→} from "@/components/ui/select";
 23→import { Spinner } from "@/components/ui/spinner";
 24→import { Switch } from "@/components/ui/switch";
 25→import { useDateRange } from "@/contexts/DateRangeContext";
 26→import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
 27→import { calculateCost, formatUsername } from "@/lib/format";
 28→import { orpc } from "@/lib/orpc";
 29→
 30→export function SessionsListPage() {
 31→	const navigate = useNavigate();
 32→	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
 33→		useDateRange();
 34→	const days = calculateDays();
 35→
 36→	const [selectedRepositories, setSelectedRepositories] = useState<string[]>(
 37→		[],
 38→	);
 39→	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
 40→
 41→	const [selectedDimension, setSelectedDimension] =
 42→		useState<DimensionAnalysisInput["dimension"]>("repository");
 43→	const [selectedMetric, setSelectedMetric] =
 44→		useState<DimensionAnalysisInput["metric"]>("session_count");
 45→	const [selectedSplitBy, setSelectedSplitBy] = useState<
 46→		DimensionAnalysisInput["dimension"] | ""
 47→	>("");
 48→	const [showPercentage, setShowPercentage] = useState(false);
 49→
 50→	const [debouncedDimension, setDebouncedDimension] =
 51→		useState<DimensionAnalysisInput["dimension"]>("repository");
 52→	const [debouncedMetric, setDebouncedMetric] =
 53→		useState<DimensionAnalysisInput["metric"]>("session_count");
 54→	const [debouncedSplitBy, setDebouncedSplitBy] = useState<
 55→		DimensionAnalysisInput["dimension"] | ""
 56→	>("");
 57→
 58→	useEffect(() => {
 59→		const timer = setTimeout(() => {
 60→			setDebouncedDimension(selectedDimension);
 61→			setDebouncedMetric(selectedMetric);
 62→			setDebouncedSplitBy(selectedSplitBy);
 63→		}, 300);
 64→		return () => clearTimeout(timer);
 65→	}, [selectedDimension, selectedMetric, selectedSplitBy]);
 66→
 67→	const { data: summary } = useAnalyticsQuery(
 68→		orpc.analytics.sessions.summary.queryOptions({ input: { days } }),
 69→	);
 70→
 71→	const { data: comparison } = useAnalyticsQuery(
 72→		orpc.analytics.sessions.summaryComparison.queryOptions({
 73→			input: { days },
 74→		}),
 75→	);
 76→
 77→	const { data: sessions, isLoading } = useAnalyticsQuery(
 78→		orpc.analytics.sessions.list.queryOptions({
 79→			input: { days, limit: 100, sortBy: "session_date", sortOrder: "desc" },
 80→		}),
 81→	);
 82→
 83→	const { data: userMappings } = useAnalyticsQuery(
 84→		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
 85→	);
 86→
 87→	const { data: dimensionData, isLoading: dimensionLoading } =
 88→		useAnalyticsQuery(
 89→			orpc.analytics.sessions.dimensionAnalysis.queryOptions({
 90→				input: {
 91→					days,
 92→					dimension: debouncedDimension,
 93→					metric: debouncedMetric,
 94→					splitBy: debouncedSplitBy || undefined,
 95→					limit: 10,
 96→				},
 97→			}),
 98→		);
 99→
100→	const userMap = useMemo(() => {
101→		const map = new Map<string, string>();
102→		if (userMappings) {
103→			for (const m of userMappings) {
104→				map.set(m.user_id, m.username);
105→			}
106→		}
107→		return map;
108→	}, [userMappings]);
109→
110→	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);
111→
112→	const columns = useMemo<ColumnDef<SessionAnalytics>[]>(
113→		() => [
114→			{
115→				accessorKey: "session_id",
116→				header: "Session ID",
117→				cell: ({ row }) => (
118→					<span className="text-accent font-mono text-xs">
119→						{row.original.session_id.slice(0, 8)}...
120→					</span>
121→				),
122→			},
123→			{
124→				accessorFn: (row) => new Date(row.session_date).getTime(),
125→				id: "date",
126→				header: "Date",
127→				cell: ({ row }) => (
128→					<div>
129→						<span className="text-foreground">
130→							{new Date(row.original.session_date).toLocaleDateString()}
131→						</span>
132→						<br />
133→						<span className="text-xs text-muted">
134→							{new Date(row.original.session_date).toLocaleTimeString()}
135→						</span>
136→					</div>
137→				),
138→			},
139→			{
140→				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
141→				id: "user",
142→				header: "User",
143→				cell: ({ row }) => (
144→					<span className="text-subheading">
145→						{formatUsername(row.original.user_id, userMapRecord)}
146→					</span>
147→				),
148→			},
149→			{
150→				accessorKey: "project_path",
151→				header: "Project",
152→				cell: ({ row }) => (
153→					<div
154→						className="max-w-xs truncate"
155→						title={row.original.git_remote || row.original.project_path}
156→					>
157→						{row.original.git_remote
158→							? row.original.git_remote.split("/").pop()
159→							: row.original.project_path.split("/").pop() ||
160→								row.original.project_path}
161→					</div>
162→				),
163→			},
164→			{
165→				accessorKey: "duration_min",
166→				header: "Duration",
167→				cell: ({ row }) => (
168→					<span className="text-foreground">
169→						{row.original.duration_min.toFixed(0)} min
170→					</span>
171→				),
172→			},
173→			{
174→				accessorKey: "success_score",
175→				header: "Success Score",
176→				cell: ({ row }) => {
177→					const score = row.original.success_score;
178→					const color =
179→						score >= 70
180→							? "text-status-success-icon"
181→							: score >= 40
182→								? "text-status-warning-icon"
183→								: "text-status-error-icon";
184→					return (
185→						<>
186→							<span className={`font-semibold ${color}`}>
187→								{score.toFixed(0)}
188→							</span>
189→							<span className="text-xs text-muted"> / 100</span>
190→						</>
191→					);
192→				},
193→			},
194→			{
195→				accessorFn: (row) => calculateCost(row.input_tokens, row.output_tokens),
196→				id: "cost",
197→				header: "Cost",
198→				cell: ({ row }) => (
199→					<span className="text-foreground font-mono">
200→						$
201→						{calculateCost(
202→							row.original.input_tokens,
203→							row.original.output_tokens,
204→						).toFixed(4)}
205→					</span>
206→				),
207→			},
208→		],
209→		[userMapRecord],
210→	);
211→
212→	const filteredSessions = useMemo(() => {
213→		if (!sessions) return [];
214→		return sessions.filter((session) => {
215→			const repoMatch =
216→				selectedRepositories.length === 0 ||
217→				(session.repository &&
218→					selectedRepositories.includes(session.repository));
219→			const userMatch =
220→				selectedUsers.length === 0 || selectedUsers.includes(session.user_id);
221→			return repoMatch && userMatch;
222→		});
223→	}, [sessions, selectedRepositories, selectedUsers]);
224→
225→	const repositories = useMemo(() => {
226→		if (!sessions) return [];
227→		return Array.from(
228→			new Set(sessions.map((s) => s.repository).filter(Boolean)),
229→		).sort() as string[];
230→	}, [sessions]);
231→
232→	const users = useMemo(() => {
233→		if (!sessions) return [];
234→		return Array.from(
235→			new Set(sessions.map((s) => s.user_id).filter(Boolean)),
236→		).sort();
237→	}, [sessions]);
238→
239→	if (isLoading) {
240→		return (
241→			<div className="px-8 py-6">
242→				<PageHeader
243→					title="Sessions"
244→					description="Analyze session interaction timing and patterns"
245→					actions={
246→						<DatePicker
247→							startDate={startDate}
248→							endDate={endDate}
249→							onStartDateChange={setStartDate}
250→							onEndDateChange={setEndDate}
251→						/>
252→					}
253→				/>
254→				<AnalyticsCard>
255→					<p className="text-center text-muted">Loading session analytics...</p>
256→				</AnalyticsCard>
257→			</div>
258→		);
259→	}
260→
261→	return (
262→		<div className="px-8 py-6">
263→			<PageHeader
264→				title="Sessions"
265→				description="Analyze session interaction timing and patterns"
266→				actions={
267→					<DatePicker
268→						startDate={startDate}
269→						endDate={endDate}
270→						onStartDateChange={setStartDate}
271→						onEndDateChange={setEndDate}
272→					/>
273→				}
274→			/>
275→
276→			{summary && comparison && (
277→				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
278→					<StatCard
279→						title="Total Sessions"
280→						value={summary.total_sessions.toLocaleString()}
281→						icon={Activity}
282→						iconColor="text-blue-600"
283→						trend={{ value: comparison.changes.total_sessions }}
284→					/>
285→					<StatCard
286→						title="Avg Session Duration"
287→						value={`${summary.avg_session_duration_min.toFixed(1)} min`}
288→						icon={Clock}
289→						iconColor="text-purple-600"
290→						trend={{ value: comparison.changes.avg_session_duration_min }}
291→					/>
292→					<StatCard
293→						title="Avg Response Time"
294→						value={`${summary.avg_response_time_sec.toFixed(1)}s`}
295→						icon={Timer}
296→						iconColor="text-green-600"
297→						trend={{ value: comparison.changes.avg_response_time_sec }}
298→					/>
299→				</div>
300→			)}
301→
302→			{/* Dimension Analysis */}
303→			<AnalyticsCard className="mb-8">
304→				<h3 className="text-lg font-semibold mb-4">
305→					Multi-Dimensional Analysis
306→				</h3>
307→				<p className="text-sm text-muted mb-6">
308→					Analyze sessions across different dimensions and metrics.
