  1→import { useTheme } from "next-themes";
  2→import { useEffect, useState } from "react";
  3→import { Navigate, Route, Routes } from "react-router-dom";
  4→import { LoginForm } from "./components/auth/login-form";
  5→import { SignupForm } from "./components/auth/signup-form";
  6→import { DashboardLayout } from "./layouts/DashboardLayout";
  7→import { authClient } from "./lib/auth-client";
  8→import { AcceptInvitationPage } from "./pages/AcceptInvitationPage";
  9→import { CreateOrgPage } from "./pages/dashboard/CreateOrgPage";
 10→import { DeveloperDetailPage } from "./pages/dashboard/DeveloperDetailPage";
 11→import { DevelopersListPage } from "./pages/dashboard/DevelopersListPage";
 12→import { ErrorsPage } from "./pages/dashboard/ErrorsPage";
 13→import { InvitationsPage } from "./pages/dashboard/InvitationsPage";
 14→import { LearningsPage } from "./pages/dashboard/LearningsPage";
 15→import { OrganizationPage } from "./pages/dashboard/OrganizationPage";
 16→import { OverviewPage } from "./pages/dashboard/OverviewPage";
 17→import { ProfilePage } from "./pages/dashboard/ProfilePage";
 18→import { ProjectDetailPage } from "./pages/dashboard/ProjectDetailPage";
 19→import { ProjectsListPage } from "./pages/dashboard/ProjectsListPage";
 20→import { ROIPage } from "./pages/dashboard/ROIPage";
 21→import { SessionDetailPage } from "./pages/dashboard/SessionDetailPage";
 22→import { SessionsListPage } from "./pages/dashboard/SessionsListPage";
 23→
 24→type Page = "login" | "signup";
 25→
 26→function getCliParams(): { cliCallback: string; state: string } | null {
 27→	const params = new URLSearchParams(window.location.search);
 28→	const cliCallback = params.get("cli_callback");
 29→	const state = params.get("state");
 30→	if (!cliCallback || !state) return null;
 31→	try {
 32→		const url = new URL(cliCallback);
 33→		if (url.hostname !== "127.0.0.1") return null;
 34→	} catch {
 35→		return null;
 36→	}
 37→	return { cliCallback, state };
 38→}
 39→
 40→function getValidRedirect(): string | null {
 41→	const params = new URLSearchParams(window.location.search);
 42→	const redirect = params.get("redirect");
 43→	if (!redirect) return null;
 44→	if (!redirect.startsWith("/") || redirect.startsWith("//")) return null;
 45→	return redirect;
 46→}
 47→
 48→function App() {
 49→	const { data: session, isPending } = authClient.useSession();
 50→	const [page, setPage] = useState<Page>("login");
 51→	const [cliRedirecting, setCliRedirecting] = useState(false);
 52→	const cliParams = getCliParams();
 53→	const { resolvedTheme } = useTheme();
 54→	const logoSrc =
 55→		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 56→
 57→	useEffect(() => {
 58→		if (!session || !cliParams || cliRedirecting) return;
 59→		setCliRedirecting(true);
 60→
 61→		fetch("/api/cli-token", { credentials: "include" })
 62→			.then((res) => res.json())
 63→			.then((data: { token: string }) => {
 64→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 65→				window.location.href = redirectUrl;
 66→			});
 67→	}, [session, cliParams, cliRedirecting]);
 68→
 69→	if (isPending) {
 70→		return (
 71→			<div className="flex min-h-screen items-center justify-center">
 72→				<p className="text-muted-foreground">Loading...</p>
 73→			</div>
 74→		);
 75→	}
 76→
 77→	if (cliRedirecting) {
 78→		return (
 79→			<div className="flex min-h-screen items-center justify-center">
 80→				<p className="text-muted-foreground">Completing CLI login...</p>
 81→			</div>
 82→		);
 83→	}
 84→
 85→	if (!session) {
 86→		return (
 87→			<div className="flex min-h-screen flex-col items-center justify-center gap-6">
 88→				<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
 89→				{page === "login" ? (
 90→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 91→				) : (
 92→					<SignupForm onSwitchToLogin={() => setPage("login")} />
 93→				)}
 94→			</div>
 95→		);
 96→	}
 97→
 98→	return (
 99→		<Routes>
100→			<Route
101→				path="/"
102→				element={<Navigate to={getValidRedirect() || "/dashboard"} replace />}
103→			/>
104→			<Route
105→				path="/invitation/:invitationId"
106→				element={<AcceptInvitationPage />}
107→			/>
108→			<Route path="/dashboard" element={<DashboardLayout />}>
109→				<Route index element={<OverviewPage />} />
110→				<Route path="developers" element={<DevelopersListPage />} />
111→				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
112→				<Route path="projects" element={<ProjectsListPage />} />
113→				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
114→				<Route path="sessions" element={<SessionsListPage />} />
115→				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
116→				<Route path="roi" element={<ROIPage />} />
117→				<Route path="errors" element={<ErrorsPage />} />
118→				<Route path="learnings" element={<LearningsPage />} />
119→				<Route path="profile" element={<ProfilePage />} />
120→				<Route path="invitations" element={<InvitationsPage />} />
121→				<Route path="organization" element={<OrganizationPage />} />
122→				<Route path="organization/new" element={<CreateOrgPage />} />
123→			</Route>
124→			<Route path="*" element={<Navigate to="/dashboard" replace />} />
125→		</Routes>
126→	);
127→}
128→
129→export default App;
