 1→import { ChevronRight } from "lucide-react";
 2→import { Link, useLocation } from "react-router-dom";
 3→
 4→const segmentLabels: Record<string, string> = {
 5→	dashboard: "Overview",
 6→	developers: "Developers",
 7→	projects: "Projects",
 8→	roi: "ROI & Business Value",
 9→	sessions: "Sessions",
10→	learnings: "Learnings",
11→	errors: "Errors",
12→	invitations: "Invitations",
13→	profile: "Profile",
14→};
15→
16→export function Breadcrumb() {
17→	const { pathname } = useLocation();
18→	const segments = pathname.split("/").filter(Boolean);
19→
20→	const crumbs = segments.map((segment, index) => {
21→		const href = `/${segments.slice(0, index + 1).join("/")}`;
22→		const label = segmentLabels[segment] || decodeURIComponent(segment);
23→		const isLast = index === segments.length - 1;
24→
25→		return { href, label, isLast };
26→	});
27→
28→	return (
29→		<nav className="flex shrink-0 items-center gap-1 text-xs text-muted h-10 px-8 bg-surface border-b border-border">
30→			{crumbs.map((crumb, index) => (
31→				<span key={crumb.href} className="flex items-center gap-1">
32→					{index > 0 && <ChevronRight className="h-3 w-3" />}
33→					{crumb.isLast ? (
34→						<span className="text-subheading">{crumb.label}</span>
35→					) : (
36→						<Link
37→							to={crumb.href}
38→							className="hover:text-foreground transition-colors"
39→						>
40→							{crumb.label}
41→						</Link>
42→					)}
43→				</span>
44→			))}
45→		</nav>
46→	);
47→}
